import React, { useEffect, useRef, useState } from 'react';
import io from 'socket.io-client';
import Peer from 'simple-peer';

const VideoCall = ({ roomId, userId, onLeave, serverUrl }) => {
  const [peers, setPeers] = useState([]);
  const [localStream, setLocalStream] = useState(null);
  const [remoteStreams, setRemoteStreams] = useState(new Map());
  const [isAudioEnabled, setIsAudioEnabled] = useState(true);
  const [isVideoEnabled, setIsVideoEnabled] = useState(true);
  const [connectionStatus, setConnectionStatus] = useState('connecting');
  const [socketId, setSocketId] = useState('');
  const [pendingParticipants, setPendingParticipants] = useState([]); // New state for pending participants

  // AI States (for future use)
  const [aiLatency, setAiLatency] = useState(0);
  const [isProcessing, setIsProcessing] = useState(false);

  const socketRef = useRef();
  const peersRef = useRef([]);
  const localVideoRef = useRef();
  const remoteVideosRef = useRef(new Map());

  useEffect(() => {
    console.log('Initializing VideoCall with roomId:', roomId, 'userId:', userId);
    console.log('Connecting to server:', serverUrl);

    // Connect to signaling server with HTTPS
    socketRef.current = io(serverUrl, {
      transports: ['websocket', 'polling'],
      reconnectionAttempts: 5,
      reconnectionDelay: 1000,
      timeout: 20000,
      forceNew: true
    });

    // Socket connection event handlers
    socketRef.current.on('connect', () => {
      console.log('✅ Socket connected with ID:', socketRef.current.id);
      setSocketId(socketRef.current.id);
      setConnectionStatus('connected');

      // Get user media with better error handling
      const constraints = {
        video: {
          width: { ideal: 640 },
          height: { ideal: 480 },
          frameRate: { ideal: 30 },
          facingMode: "user",
          resizeMode: "crop-and-scale"
        },
        audio: {
          echoCancellation: true,
          noiseSuppression: true,
          autoGainControl: true,
          channelCount: 2,
          sampleRate: 48000
        }
      };

      console.log('Requesting media with constraints:', constraints);

      navigator.mediaDevices.getUserMedia(constraints)
        .then(stream => {
          console.log('✅ Got local stream');
          console.log('Video tracks:', stream.getVideoTracks().length);
          console.log('Audio tracks:', stream.getAudioTracks().length);

          stream.getVideoTracks().forEach(track => {
            console.log('Video track settings:', track.getSettings());
          });

          setLocalStream(stream);
          if (localVideoRef.current) {
            localVideoRef.current.srcObject = stream;
          }

          // Join room after getting stream
          console.log('Emitting join-room event:', { roomId, userId });
          socketRef.current.emit('join-room', { roomId, userId });
        })
        .catch(error => {
          console.error('❌ Error accessing media devices:', error);
          console.error('Error name:', error.name);
          console.error('Error message:', error.message);

          setConnectionStatus('error');

          // Show user-friendly message based on error
          if (error.name === 'NotAllowedError' || error.message.includes('perm')) {
            alert('Camera access denied. Please allow camera and microphone access.\n\nClick the camera icon in the address bar and select "Allow".');
          } else if (error.name === 'NotFoundError') {
            alert('No camera or microphone found. Please connect a camera and try again.');
          } else if (error.name === 'NotReadableError' || error.message.includes('starting')) {
            alert('Camera is already in use by another application. Please close other apps using the camera (Zoom, Teams, etc.) and refresh.');
          } else if (error.name === 'AbortError') {
            alert('Failed to start camera. This might be a driver issue. Try:\n1. Restart your browser\n2. Check if camera works in other apps\n3. Update camera drivers');
          } else {
            alert(`Could not access camera/microphone: ${error.message}`);
          }
        });
    });

    socketRef.current.on('connect_error', (error) => {
      console.error('❌ Socket connection error:', error);
      setConnectionStatus('error');
    });

    socketRef.current.on('disconnect', (reason) => {
      console.log('Socket disconnected:', reason);
      setConnectionStatus('connecting');
    });

    socketRef.current.on('reconnect', (attemptNumber) => {
      console.log('Socket reconnected after', attemptNumber, 'attempts');
      setConnectionStatus('connected');
    });

    // Room events
    socketRef.current.on('room-joined', ({ participants, isHost }) => {
      console.log('✅ Successfully joined room! Participants:', participants);
      setConnectionStatus('connected');

      // Create peer connections for existing participants
      participants.forEach(participant => {
        if (participant.socketId !== socketRef.current.id) {
          if (localStream) {
            createPeer(participant.socketId, true, localStream);
          } else {
            setPendingParticipants(prev => [...prev, { socketId: participant.socketId, initiator: true }]);
          }
        }
      });
    });

    socketRef.current.on('user-connected', ({ userId, socketId }) => {
      console.log('👤 User connected:', userId, socketId);
      if (socketId !== socketRef.current.id) {
        if (localStream) {
          createPeer(socketId, false, localStream);
        } else {
          setPendingParticipants(prev => [...prev, { socketId, initiator: false }]);
        }
      }
    });

    socketRef.current.on('user-disconnected', ({ socketId, userId }) => {
      console.log('👤 User disconnected:', userId);

      // Remove peer
      const peerIndex = peersRef.current.findIndex(p => p.peerID === socketId);
      if (peerIndex !== -1) {
        peersRef.current[peerIndex].peer.destroy();
        peersRef.current.splice(peerIndex, 1);
      }

      // Remove remote video
      const videoElement = remoteVideosRef.current.get(socketId);
      if (videoElement) {
        videoElement.srcObject = null;
        videoElement.remove();
        remoteVideosRef.current.delete(socketId);
      }

      setPeers(peersRef.current.map(p => p.peerID));
      setRemoteStreams(new Map(remoteVideosRef.current));
    });

    // WebRTC signaling events
    socketRef.current.on('offer', ({ offer, from }) => {
      console.log('📞 Received offer from:', from);
      const peerExists = peersRef.current.find(p => p.peerID === from);
      if (!peerExists) {
        if (localStream) {
          createPeer(from, false, localStream, offer);
        } else {
          setPendingParticipants(prev => [...prev, { socketId: from, initiator: false, offer }]);
        }
      }
    });

    socketRef.current.on('answer', ({ answer, from }) => {
      console.log('📞 Received answer from:', from);
      const peer = peersRef.current.find(p => p.peerID === from);
      if (peer) {
        peer.peer.signal(answer);
      }
    });

    socketRef.current.on('ice-candidate', ({ candidate, from }) => {
      console.log('📞 Received ICE candidate from:', from);
      const peer = peersRef.current.find(p => p.peerID === from);
      if (peer && candidate) {
        peer.peer.signal(candidate);
      }
    });

    socketRef.current.on('error', ({ message }) => {
      console.error('Room error:', message);

      if (message === 'Room not found') {
        alert('This room no longer exists. Please create a new room.');
        setTimeout(() => onLeave(), 2000);
      } else if (message === 'Room is full') {
        alert('This room is full. Please try another room or create a new one.');
        setTimeout(() => onLeave(), 2000);
      }
    });

    // Cleanup on unmount
    return () => {
      console.log('Cleaning up VideoCall component');

      peersRef.current.forEach(peer => {
        if (peer.peer) {
          peer.peer.destroy();
        }
      });

      if (localStream) {
        localStream.getTracks().forEach(track => {
          track.stop();
        });
      }

      if (socketRef.current) {
        socketRef.current.disconnect();
      }
    };
  }, [roomId, userId, serverUrl]);

  // Effect to create peers for pending participants once localStream is available
  useEffect(() => {
    if (localStream && pendingParticipants.length > 0) {
      console.log("Local stream is now available. Creating peers for pending participants:", pendingParticipants);
      pendingParticipants.forEach(participant => {
        if (participant.socketId !== socketRef.current.id) {
          createPeer(participant.socketId, participant.initiator, localStream, participant.offer);
        }
      });
      setPendingParticipants([]); // Clear pending participants after processing
    }
  }, [localStream, pendingParticipants]);

  const createPeer = (targetSocketId, initiator, stream, offer = null) => {
    console.log('Creating peer connection:', {
      target: targetSocketId,
      initiator,
      hasOffer: !!offer,
      streamExists: !!stream
    });

    const peer = new Peer({
      initiator: initiator,
      stream: stream,
      trickle: true,
      config: {
        iceServers: [
          { urls: 'stun:stun.l.google.com:19302' },
          { urls: 'stun:stun1.l.google.com:19302' },
          { urls: 'stun:stun2.l.google.com:19302' },
          { urls: 'stun:stun3.l.google.com:19302' },
          { urls: 'stun:stun4.l.google.com:19302' }
        ]
      }
    });

    peersRef.current.push({
      peerID: targetSocketId,
      peer: peer
    });

    setPeers(peersRef.current.map(p => p.peerID));

    peer.on('signal', signal => {
      console.log('📡 Signal from peer:', targetSocketId, signal.type);

      if (initiator && !offer) {
        socketRef.current.emit('offer', {
          offer: signal,
          to: targetSocketId,
          from: socketRef.current.id
        });
      } else if (offer && signal.type === 'answer') {
        socketRef.current.emit('answer', {
          answer: signal,
          to: targetSocketId,
          from: socketRef.current.id
        });
      } else if (signal.type === 'candidate') {
        socketRef.current.emit('ice-candidate', {
          candidate: signal,
          to: targetSocketId,
          from: socketRef.current.id
        });
      }
    });

    peer.on('stream', stream => {
      console.log('🎥 Received stream from peer:', targetSocketId);

      let videoElement = remoteVideosRef.current.get(targetSocketId);
      if (!videoElement) {
        videoElement = document.createElement('video');
        videoElement.id = `remote-video-${targetSocketId}`;
        videoElement.autoplay = true;
        videoElement.playsInline = true;
        videoElement.className = "w-full h-full object-cover";
        remoteVideosRef.current.set(targetSocketId, videoElement);
      }

      videoElement.srcObject = stream;
      setRemoteStreams(new Map(remoteVideosRef.current));
    });

    peer.on('connect', () => {
      console.log('✅ Peer connection established with:', targetSocketId);
    });

    peer.on('error', err => {
      console.error('❌ Peer error with', targetSocketId, ':', err);
    });

    peer.on('close', () => {
      console.log('🔒 Peer connection closed with:', targetSocketId);
    });

    if (offer) {
      console.log('Signaling offer to peer');
      peer.signal(offer);
    }

    return peer;
  };

  const toggleAudio = () => {
    if (localStream) {
      localStream.getAudioTracks().forEach(track => {
        track.enabled = !track.enabled;
        setIsAudioEnabled(track.enabled);
      });
    }
  };

  const toggleVideo = () => {
    if (localStream) {
      localStream.getVideoTracks().forEach(track => {
        track.enabled = !track.enabled;
        setIsVideoEnabled(track.enabled);
      });
    }
  };

  return (
    <div className="flex flex-col h-screen bg-gray-900 text-white">
      <header className="p-4 bg-gray-800 shadow-md flex justify-between items-center">
        <h1 className="text-2xl font-bold">Video Call: Room {roomId}</h1>
        <div className="flex items-center space-x-4">
          <span className="text-sm">Status: {connectionStatus}</span>
          <button
            onClick={toggleAudio}
            className={`p-2 rounded-full ${isAudioEnabled ? 'bg-green-500' : 'bg-red-500'} text-white`}
          >
            {isAudioEnabled ? '🎤' : '🔇'}
          </button>
          <button
            onClick={toggleVideo}
            className={`p-2 rounded-full ${isVideoEnabled ? 'bg-green-500' : 'bg-red-500'} text-white`}
          >
            {isVideoEnabled ? '📹' : '📷'}
          </button>
          <button
            onClick={onLeave}
            className="bg-red-600 hover:bg-red-700 text-white font-bold py-2 px-4 rounded"
          >
            Leave Room
          </button>
        </div>
      </header>

      <main className="flex-1 flex flex-wrap justify-center items-center p-4 gap-4 overflow-auto">
        {/* Local Video */}
        <div className="relative w-full md:w-1/2 lg:w-1/3 xl:w-1/4 h-64 bg-gray-700 rounded-lg shadow-lg overflow-hidden">
          <video
            ref={localVideoRef}
            autoPlay
            playsInline
            muted
            className="w-full h-full object-cover transform scale-x-[-1]"
          />
          <div className="absolute bottom-2 left-2 bg-black bg-opacity-50 text-white text-xs px-2 py-1 rounded">You</div>
        </div>

        {/* Remote Videos */}
        {Array.from(remoteVideosRef.current.entries()).map(([socketId, videoElement]) => (
          <div key={socketId} className="relative w-full md:w-1/2 lg:w-1/3 xl:w-1/4 h-64 bg-gray-700 rounded-lg shadow-lg overflow-hidden">
            {/* The video element is managed directly by remoteVideosRef, so we just need a container */}
            <div id={`remote-video-container-${socketId}`} className="w-full h-full">
              {/* This div will be replaced by the actual video element from remoteVideosRef */}
            </div>
            <div className="absolute bottom-2 left-2 bg-black bg-opacity-50 text-white text-xs px-2 py-1 rounded">Participant {socketId.substring(0, 4)}</div>
          </div>
        ))}
      </main>
    </div>
  );
};

export default VideoCall;
